package org.example.controller;
import jakarta.validation.Valid; import org.example.model.dto.NotificationDto; import org.example.model.entity.Notification; import org.example.model.enums.*; import org.example.service.NotificationService; import org.springframework.web.bind.annotation.*; import java.util.List;
@RestController @RequestMapping("/notifications")
public class NotificationController { private final NotificationService service; public NotificationController(NotificationService service){this.service=service;}
    @PostMapping("/add") public Notification create(@RequestBody @Valid NotificationDto dto){return service.createNotification(dto);} @GetMapping("/all") public List<Notification> all(){return service.getAllNotifications();}
    @GetMapping("/{id}") public Notification byId(@PathVariable Long id){return service.getNotificationById(id);} @GetMapping("/status/{status}") public List<Notification> byStatus(@PathVariable NotificationStatus status){return service.getNotificationsByStatus(status);} @GetMapping("/channel/{channel}") public List<Notification> byChannel(@PathVariable NotificationChannel channel){return service.getNotificationsByChannel(channel);} @GetMapping("/recipient/{id}") public List<Notification> byRecipient(@PathVariable Long id){return service.getNotificationsByRecipientId(id);} @PutMapping("/{id}/sent") public Notification sent(@PathVariable Long id){return service.markAsSent(id);} @DeleteMapping("/{id}") public void delete(@PathVariable Long id){service.deleteNotification(id);} }
